/bin/zsh -lc "node <<'NODE'
const assert = require('assert');
const { parseFrontMatter } = require('./src/markdown/frontmatter');

assert.deepStrictEqual(
  parseFrontMatter('---\\ntitle: Hello\\nauthor: Ada\\n---\\n# Post'),
  { metadata: { title: 'Hello', author: 'Ada' }, body: '# Post' },
);

assert.deepStrictEqual(
  parseFrontMatter('Intro\\n---\\nnot metadata'),
  { metadata: {}, body: 'Intro\\n---\\nnot metadata' },
);

assert.deepStrictEqual(
  parseFrontMatter('---\\ntitle: Missing close\\n# Post'),
  { metadata: {}, body: '---\\ntitle: Missing close\\n# Post' },
);

assert.deepStrictEqual(
  parseFrontMatter('---\\r\\ntitle: CRLF\\r\\n---\\r\\nBody'),
  { metadata: { title: 'CRLF' }, body: 'Body' },
);
NODE"

